import sys
from collections import defaultdict

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    A = list(map(int, input[1:]))

    next_person = {}
    front = -1

    for i in range(N):
        if A[i] == -1:
            front = i + 1  # person numbers are 1-based
        else:
            next_person[A[i]] = i + 1  # A[i] is the current person, i+1 is the next

    result = []
    current = front
    while current != -1:
        result.append(str(current))
        current = next_person.get(current, -1)

    print(' '.join(result))

if __name__ == "__main__":
    main()
